        "code": "import pandas as pd\nfrom statsmodels.tsa.seasonal import seasonal_decompose\nfrom statsmodels.tsa.arima.model import ARIMA\n\n# 표(month=월, n_claims=건수)를 xl()로 참조하세요 — 표 이름/범위는 데이터에 맞게 바꿉니다\nraw = xl(\"Table1[#All]\", headers=True)\nts = (\n    raw.assign(month=pd.to_datetime(raw[\"month\"]))   # month 열을 날짜형으로\n       .set_index(\"month\")[\"n_claims\"]\n       .asfreq(\"MS\")\n)\n\n# ① 추세·계절성 분해 (분해 그림만 셀에 보려면 이 줄을 별도 =PY() 셀의 '마지막 식'으로 두세요)\nseasonal_decompose(ts, model=\"additive\").plot()\n\n# ② ARIMA 적합 — (p, d, q) = (자기회귀, 차분, 이동평균) 차수\nmodel = ARIMA(ts, order=(1, 1, 1),\n              seasonal_order=(1, 1, 1, 12)).fit()   # 월별 계절성 12\nprint(model.summary())   # 요약표는 셀이 아니라 진단(Diagnostics) 창에 표시됩니다\n\n# ③ 12개월 예측 + 95% 예측구간\nfc = model.get_forecast(steps=12)\nout = fc.summary_frame()          # mean, mean_ci_lower, mean_ci_upper\nout.round(1)                      # 마지막 식 → 예측표가 셀에 반환됩니다"
