        "code": "import matplotlib.pyplot as plt\nfrom statsmodels.duration.survfunc import SurvfuncRight   # lifelines 대체(엑셀 미포함)\n\n# 표(duration=관찰기간(월), event=1 해지/0 중도절단, channel=채널)를 xl()로 참조\ndf = xl(\"Table1[#All]\", headers=True)\n\n# duration: 관찰 기간(월), event: 1=해지 발생, 0=관찰 종료(중도절단)\nfig, ax = plt.subplots()\nfor channel, g in df.groupby(\"channel\"):\n    sf = SurvfuncRight(g[\"duration\"], g[\"event\"])   # Kaplan-Meier 유지율 추정(모수 없이 관측만)\n    below = sf.surv_times[sf.surv_prob <= 0.5]\n    med = float(below[0]) if len(below) else float(\"nan\")   # 유지율이 50%가 되는 시점\n    ax.step(sf.surv_times, sf.surv_prob, where=\"post\", label=f\"{channel} (중위 {med:.0f}월)\")\n    print(f\"{channel}: 중위 생존시간 = {med:.1f}월\")   # 값은 진단창에 표시\n\nax.set_ylim(0, 1)\nax.set_xlabel(\"경과월\")\nax.set_ylabel(\"유지율\")\nax.legend()\nfig   # 마지막 식 = 유지율 곡선 그림이 셀에 이미지로 반환됩니다"
