        "code": "import numpy as np\nimport pandas as pd\nfrom statsmodels.duration.hazard_regression import PHReg   # lifelines의 CoxPHFitter 대체\n\n# df: 앞 섹션에서 xl()로 불러온 데이터(duration, event, age, premium_ratio, has_rider)\nexog = df[[\"age\", \"premium_ratio\", \"has_rider\"]].astype(float)\ncox = PHReg(df[\"duration\"], exog, status=df[\"event\"]).fit()   # Cox 비례위험 모형 적합\nprint(cox.summary())          # 계수·표준오차 등 상세는 진단창에서 확인\n\n# exp(coef) = 위험비(HR): 1.3이면 해지 위험 30%↑, 1보다 작으면 낮춤\nhr = pd.Series(np.exp(np.asarray(cox.params)), index=exog.columns, name=\"HR(위험비)\")\nhr.round(3).to_frame()        # 마지막 식 → 위험비(HR) 표가 셀에 반환됩니다"
