        "sameAsOriginal": false,
        "code": "import numpy as np\nimport pandas as pd\nfrom scipy import stats\nfrom statsmodels.duration.hazard_regression import PHReg\n\ncols_x = [\"age\", \"premium_ratio\", \"has_rider\"]\nX = df[cols_x].astype(float)\n\n# ① 비례위험 가정 점검 — lifelines의 check_assumptions는 없으므로 statsmodels 잔차로 직접 점검\n#    표준화 Schoenfeld 잔차와 사건시각의 상관이 0에 가까워야 비례위험 가정이 성립합니다.\nbase = PHReg(df[\"duration\"], X, status=df[\"event\"]).fit()\nsch = np.asarray(base.schoenfeld_residuals)      # 사건 발생행만 값, 중도절단은 NaN\nmask = ~np.isnan(sch).any(axis=1)\netime = df[\"duration\"].to_numpy()[mask]\nfor j, name in enumerate(cols_x):\n    r, p = stats.spearmanr(etime, sch[mask, j])\n    flag = \"  ← 비례가정 의심(p<0.05)\" if p < 0.05 else \"\"\n    print(f\"  {name:14s} corr(time,resid)={r:+.3f}  p={p:.3f}{flag}\")\n\n# ② 층화 — 집단(channel)별 기저위험을 분리(계수는 공유). PHReg는 strata 인자를 지원합니다.\ncox_st = PHReg(df[\"duration\"], X, status=df[\"event\"], strata=df[\"channel\"]).fit()\nprint(\"[층화 Cox] HR:\", np.round(np.exp(np.asarray(cox_st.params)), 3))\n\n# ③ 소량 규제(elastic net) — 변수가 많거나 수렴이 불안정할 때 계수를 안정화(alpha 0.01~0.1)\ncox_pen = PHReg(df[\"duration\"], X, status=df[\"event\"]).fit_regularized(alpha=0.1)\nprint(\"[규제] 계수:\", np.round(np.asarray(cox_pen.params), 3))\n\n# ④ 모형 비교 — 부분우도 기반 AIC(작을수록 좋음). C-index는 statsmodels 기본 미제공이라 생략.\ndef aic_partial(res):\n    return -2.0 * res.llf + 2.0 * len(res.params)\n# 주의: 층화 모형은 부분우도의 기준이 달라 AIC를 다른 모형과 직접 비교하면 안 됩니다.\npd.DataFrame(\n    {\"logL\": [base.llf, cox_st.llf],\n     \"AIC(부분우도)\": [aic_partial(base), aic_partial(cox_st)]},\n    index=[\"기본\", \"층화(channel)\"],\n).round(1)   # 마지막 식 → 모형 비교표가 셀에 반환됩니다"
