        "code": "from sklearn.decomposition import PCA\nfrom sklearn.preprocessing import StandardScaler\nimport pandas as pd\nimport matplotlib.pyplot as plt\n\n# 이 셀은 위 '2개 성분 지정' 셀에서 만든 X(변수 DataFrame)·y(라벨)를 이어서 씁니다.\n# (엑셀의 Python은 워크북 위쪽 셀의 변수를 아래 셀에서 그대로 사용하므로 그 셀 아래에 두세요)\nX_scaled = StandardScaler().fit_transform(X)\n\npca = PCA()\nZ = pca.fit_transform(X_scaled)\n\n# 성분별 설명분산 — 누적 80~90%까지 채택 (print는 진단창에 표시)\nratio = pca.explained_variance_ratio_\nprint(pd.Series(ratio.cumsum().round(3), name=\"누적설명분산\"))\n\n# 첫 두 성분으로 산점도 (라벨 색)\nplt.scatter(Z[:, 0], Z[:, 1], c=y, s=8, alpha=0.5, cmap=\"coolwarm\")\nplt.xlabel(\"PC1\"); plt.ylabel(\"PC2\")\n\n# 로딩: 각 주성분이 어떤 변수의 조합인지 (표는 진단창에 표시)\nloadings = pd.DataFrame(pca.components_[:2].T,\n                        index=X.columns, columns=[\"PC1\", \"PC2\"])\nprint(loadings.round(3))\n\n# 마지막 식으로 그림 객체를 반환 — 산점도가 셀에 이미지로 표시됩니다\nplt.gcf()"
